// Attach business context to every review item.
// Also normalises starRating from GBP's string enum (ONE/TWO/.../FIVE) to a number.
// FIX: the original workflow compared star ratings to numbers — GBP returns strings.

const ratingMap = { ONE: 1, TWO: 2, THREE: 3, FOUR: 4, FIVE: 5 };

const businessName = $('Loop Businesses').first().json.businessName;
const locationId   = $('Loop Businesses').first().json.locationId;
const alertEmail   = $('Loop Businesses').first().json.alertEmail;

return items.map(item => ({
  json: {
    ...item.json,
    businessName,
    locationId,
    alertEmail,
    starRatingNum: ratingMap[item.json.starRating] ?? 0,
    reviewerName:  item.json.reviewer?.displayName ?? 'A customer',
    reviewText:    item.json.comment ?? '(no review text left)'
  }
}));

// ── DEDUPLICATION ─────────────────────────────────────────────────────────
// Uses n8n static workflow data — no external database needed.
// Tracks processed review IDs with timestamps.
// Auto-prunes entries older than 90 days to prevent unbounded growth.
//
// WHY THIS IS NEEDED:
// Negative/neutral reviews never get a reply posted, so reviewReply stays null.
// Without this, the same negative review would trigger a new email every hour.

const staticData = $getWorkflowStaticData('global');
const now = Date.now();
const PRUNE_AGE_MS = 90 * 24 * 60 * 60 * 1000;

if (!staticData.processed) staticData.processed = {};

// Prune stale entries
for (const id of Object.keys(staticData.processed)) {
  if (now - staticData.processed[id] > PRUNE_AGE_MS) {
    delete staticData.processed[id];
  }
}

const newItems = [];
for (const item of items) {
  const reviewId = item.json.name; // GBP review resource name is the unique identifier
  if (staticData.processed[reviewId]) {
    continue; // Already processed — skip silently
  }
  staticData.processed[reviewId] = now;
  newItems.push(item);
}

return newItems;

